def zigzag_iterate(lists, n):
    result = []
    k = len(lists)
    indices = [0] * k
    active = [i for i, lst in enumerate(lists) if lst]

    while active and len(result) < n:
        next_active = []
        for i in active:
            if len(result) >= n:
                break
            idx = indices[i]
            if idx < len(lists[i]):
                result.append(lists[i][idx])
                indices[i] += 1
                if indices[i] < len(lists[i]):
                    next_active.append(i)
        active = next_active

    return result
