def word_chain_score(words):
    n = len(words)
    if n == 0:
        return 0

    starts = [w[0] for w in words]
    ends = [w[-1] for w in words]
    lengths = [len(w) for w in words]

    from functools import lru_cache

    @lru_cache(None)
    def best(last_idx, used_mask):
        best_score = 0
        last_char = ends[last_idx]
        for i in range(n):
            if not (used_mask & (1 << i)) and starts[i] == last_char:
                score = lengths[i] + best(i, used_mask | (1 << i))
                if score > best_score:
                    best_score = score
        return best_score

    ans = 0
    for i in range(n):
        ans = max(ans, lengths[i] + best(i, 1 << i))
    return ans
