def water_flow(grid):
    if not grid or not grid[0]:
        return []

    rows, cols = len(grid), len(grid[0])
    memo = [[None] * cols for _ in range(rows)]

    # Priority order for ties: up, left, right, down
    directions = [(-1, 0), (0, -1), (0, 1), (1, 0)]

    def sink(r, c):
        if memo[r][c] is not None:
            return memo[r][c]

        best_r, best_c = r, c
        best_h = grid[r][c]

        for dr, dc in directions:
            nr, nc = r + dr, c + dc
            if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] < best_h:
                best_h = grid[nr][nc]
                best_r, best_c = nr, nc

        if (best_r, best_c) == (r, c):
            memo[r][c] = [r, c]
        else:
            memo[r][c] = sink(best_r, best_c)

        return memo[r][c]

    return [[sink(r, c) for c in range(cols)] for r in range(rows)]
