from collections import deque, defaultdict

def teleporter_bfs(grid):
    n = len(grid)
    if n == 0:
        return -1

    # Map teleporter id -> list of its coordinates
    teleports = defaultdict(list)
    for i in range(n):
        for j in range(n):
            if grid[i][j] >= 2:
                teleports[grid[i][j]].append((i, j))

    # If start or end is a wall, impossible
    if grid[0][0] == 1 or grid[n - 1][n - 1] == 1:
        return -1

    dist = [[-1] * n for _ in range(n)]
    q = deque([(0, 0)])
    dist[0][0] = 0

    dirs = [(1, 0), (-1, 0), (0, 1), (0, -1)]

    while q:
        x, y = q.popleft()
        d = dist[x][y]

        if (x, y) == (n - 1, n - 1):
            return d

        # Normal 4-directional movement
        for dx, dy in dirs:
            nx, ny = x + dx, y + dy
            if 0 <= nx < n and 0 <= ny < n and grid[nx][ny] != 1 and dist[nx][ny] == -1:
                cell = grid[nx][ny]
                # Move onto empty cell or wall-checked teleporter cell
                if cell == 0:
                    dist[nx][ny] = d + 1
                    q.append((nx, ny))
                else:
                    # Enter teleporter cell: +1, then teleport instantly: +1 more total
                    tid = cell
                    if len(teleports[tid]) == 2:
                        # teleport to the matching pair
                        a, b = teleports[tid]
                        tx, ty = b if (nx, ny) == a else a
                        if dist[tx][ty] == -1:
                            dist[tx][ty] = d + 2
                            q.append((tx, ty))
                    else:
                        # If malformed teleporter (not exactly a pair), treat as passable cell
                        dist[nx][ny] = d + 1
                        q.append((nx, ny))

    return -1
