def find_conflict_groups(events):
    def overlap(event1, event2):
        return event1[1] < event2[2] and event1[2] > event2[1]

    def merge_groups(groups, new_event):
        new_group = [new_event]
        for group in groups:
            if any(overlap(event, new_event) for event in group):
                new_group.extend(group)
            else:
                groups.append(group)
        groups.append(new_group)

    sorted_events = sorted(events, key=lambda x: x[1])
    conflict_groups = []
    for event in sorted_events:
        merge_groups(conflict_groups, event)
    return conflict_groups
