def evaluate_expression(expr):
    def evaluate_helper(tokens):
        stack = []
        i = 0
        while i < len(tokens):
            if tokens[i] == '(':
                j = i
                count = 1
                while count != 0:
                    j += 1
                    if tokens[j] == '(':
                        count += 1
                    elif tokens[j] == ')':
                        count -= 1
                stack.append(evaluate_helper(tokens[i+1:j]))
                i = j
            elif tokens[i].isdigit():
                stack.append(int(tokens[i]))
            elif tokens[i] in {'+', '-', '*', '/'}:
                stack.append(tokens[i])
            i += 1

        i = 0
        while i < len(stack):
            if stack[i] == '*':
                stack[i-1] = stack[i-1] * stack[i+1]
                stack.pop(i)
                stack.pop(i)
                i -= 1
            elif stack[i] == '/':
                stack[i-1] = int(stack[i-1] / stack[i+1])
                stack.pop(i)
                stack.pop(i)
                i -= 1
            i += 1

        i = 0
        while i < len(stack):
            if stack[i] == '+':
                stack[i-1] = stack[i-1] + stack[i+1]
                stack.pop(i)
                stack.pop(i)
                i -= 1
            elif stack[i] == '-':
                stack[i-1] = stack[i-1] - stack[i+1]
                stack.pop(i)
                stack.pop(i)
                i -= 1
            i += 1

        return stack[0]

    tokens = expr.replace('(', ' ( ').replace(')', ' ) ').split()
    return evaluate_helper(tokens)

