def spiral_coords(n):
    if n < 1:
        raise ValueError("n must be 1-indexed and >= 1")

    x = y = 0
    if n == 1:
        return (x, y)

    # Directions: right, up, left, down (counter-clockwise spiral)
    dirs = [(1, 0), (0, 1), (-1, 0), (0, -1)]

    step_len = 1
    dir_idx = 0
    pos = 1  # position 1 is (0,0)

    while pos < n:
        for _ in range(2):  # each length repeats for two directions
            dx, dy = dirs[dir_idx % 4]
            for _ in range(step_len):
                if pos >= n:
                    return (x, y)
                x += dx
                y += dy
                pos += 1
            dir_idx += 1
        step_len += 1

    return (x, y)
