import re

def evaluate_expression(expr):
    def apply_op(op, a, b):
        if op == '+':
            return a + b
        if op == '-':
            return a - b
        if op == '*':
            return a * b
        if op == '/':
            return int(a / b)  # truncate toward zero

    tokens = re.findall(r'\d+|[()+\-*/]', expr.replace(' ', ''))
    values = []
    ops = []

    def precedence(op):
        if op in ('*', '/'):
            return 2
        return 1

    def reduce_once():
        op = ops.pop()
        b = values.pop()
        a = values.pop()
        values.append(apply_op(op, a, b))

    i = 0
    while i < len(tokens):
        tok = tokens[i]

        if tok.isdigit():
            values.append(int(tok))
        elif tok == '(':
            ops.append(tok)
        elif tok == ')':
            while ops and ops[-1] != '(':
                reduce_once()
            ops.pop()  # remove '('
        else:  # operator
            while ops and ops[-1] in ('+', '-', '*', '/') and precedence(ops[-1]) >= precedence(tok):
                reduce_once()
            ops.append(tok)

        i += 1

    while ops:
        reduce_once()

    return values[0]
