def teleporter_bfs(grid):
    n = len(grid)
    if n == 0 or len(grid[0]) != n:
        return -1

    # Build teleporter locations by id (>=2). Each id appears exactly twice.
    pos_by_id = defaultdict(list)
    for r in range(n):
        for c in range(n):
            v = grid[r][c]
            if isinstance(v, int) and v >= 2:
                pos_by_id[v].append((r, c))

    # Helper: where to go after stepping onto (r,c) with teleporter id v.
    pair_dest = {}
    for tid, locs in pos_by_id.items():
        if len(locs) != 2:
            continue
        a, b = locs
        pair_dest[a] = b
        pair_dest[b] = a

    INF = 10**18
    dist = [[INF] * n for _ in range(n)]
    dist[0][0] = 0
    q = deque([(0, 0)])

    def in_bounds(r, c):
        return 0 <= r < n and 0 <= c < n

    # Movement cost:
    # - normal cell: +1 for moving onto it
    # - teleporter cell: +2 total from current cell (enter + teleport)
    while q:
        r, c = q.popleft()
        d = dist[r][c]
        if (r, c) == (n - 1, n - 1):
            return d

        for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            nr, nc = r + dr, c + dc
            if not in_bounds(nr, nc):
                continue
            cell = grid[nr][nc]
            if cell == 1:
                continue
            if cell >= 2 and (nr, nc) in pair_dest:
                tr, tc = pair_dest[(nr, nc)]
                nd = d + 2
                if nd < dist[tr][tc]:
                    dist[tr][tc] = nd
                    q.append((tr, tc))
            else:
                if d + 1 < dist[nr][nc]:
                    dist[nr][nc] = d + 1
                    q.append((nr, nc))

    return -1 if dist[n - 1][n - 1] == INF else dist[n - 1][n - 1]
