from collections import defaultdict
from typing import List, Tuple

def find_conflict_groups(events: List[Tuple[str, float, float]]) -> List[List[Tuple[str, float, float]]]:
    def overlaps(a: Tuple[str, float, float], b: Tuple[str, float, float]) -> bool:
        _, a_start, a_end = a
        _, b_start, b_end = b
        return a_start < b_end and b_start < a_end

    n = len(events)
    parent = list(range(n))
    rank = [0] * n

    def find(x: int) -> int:
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    def union(x: int, y: int) -> None:
        rx, ry = find(x), find(y)
        if rx == ry:
            return
        if rank[rx] < rank[ry]:
            parent[rx] = ry
        elif rank[rx] > rank[ry]:
            parent[ry] = rx
        else:
            parent[ry] = rx
            rank[rx] += 1

    # Union any overlapping pairs; transitive closure is handled by DSU.
    for i in range(n):
        for j in range(i + 1, n):
            if overlaps(events[i], events[j]):
                union(i, j)

    groups_by_root = defaultdict(list)
    for idx, ev in enumerate(events):
        groups_by_root[find(idx)].append(ev)

    # Sort events within groups, then sort groups by earliest start time.
    groups = []
    for group_events in groups_by_root.values():
        group_events.sort(key=lambda t: t[1])  # start time
        groups.append(group_events)

    groups.sort(key=lambda g: g[0][1])  # earliest start time
    return groups
