def flatten_dict(d, prefix=""):
    out = {}

    def join_key(base, key):
        if base:
            return f"{base}.{key}"
        return str(key)

    if isinstance(d, dict):
        items = d.items()
    else:
        items = [(None, d)]

    for k, v in items:
        if isinstance(d, dict):
            new_prefix = join_key(prefix, k)
        else:
            new_prefix = prefix

        if isinstance(v, dict):
            out.update(flatten_dict(v, new_prefix))
        elif isinstance(v, list):
            for i, item in enumerate(v):
                idx_prefix = f"{new_prefix}[{i}]"
                if isinstance(item, dict):
                    out.update(flatten_dict(item, idx_prefix))
                elif isinstance(item, list):
                    out.update(flatten_dict(item, idx_prefix))
                else:
                    out[idx_prefix] = item
        else:
            if new_prefix == "" and k is None:
                out[prefix] = v
            else:
                out[new_prefix] = v

    return out
