def word_chain_score(words):
    def dfs(word, visited):
        max_score = len(word)
        last_letter = word[-1]
        for next_word in words:
            if next_word not in visited and next_word[0] == last_letter:
                visited.add(next_word)
                max_score = max(max_score, len(word) + dfs(next_word, visited))
                visited.remove(next_word)
        return max_score

    max_chain_score = 0
    for word in words:
        max_chain_score = max(max_chain_score, dfs(word, {word}))

    return max_chain_score
