def find_conflict_groups(events):
    def overlap(event1, event2):
        start_a, end_a = event1[1], event1[2]
        start_b, end_b = event2[1], event2[2]
        return start_a < end_b and start_b < end_a

    def find_group(event, remaining_events):
        group = [event]
        to_check = [event]
        while to_check:
            current = to_check.pop()
            for other in remaining_events[:]:
                if overlap(current, other):
                    group.append(other)
                    to_check.append(other)
                    remaining_events.remove(other)
        return group

    events = sorted(events, key=lambda x: x[1])
    conflict_groups = []
    while events:
