                    return value, index + 1  # Skip the closing ')'
                else:
                    start = index
                    while index < len(expr) and expr[index].isdigit():
                        index += 1
                    return int(expr[start:index]), index

            value, index = parse_factor(index)
            while index < len(expr) and expr[index] in "*/":
                op = expr[index]
                next_value, index = parse_factor(index + 1)
                if op == '*':
                    value *= next_value
                elif op == '/':
                    value = int(value / next_value)  # Truncate towards zero
            return value, index

        value, index = parse_term(index)
        while index < len(expr) and expr[index] in "+-":
            op = expr[index]
            next_value, index = parse_term(index + 1)
            if op == '+':
                value += next_value
            elif op == '-':
