def word_chain_score(words):
    from functools import lru_cache

    # Create a list of words for easy indexing
    word_list = words
    n = len(words)

    # Build adjacency list: for each word, find words that can follow it
    adjacency = [[] for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if i != j and word_list[i][-1] == word_list[j][0]:
                adjacency[i].append(j)

    @lru_cache(None)
    def dfs(current_index, used_mask):
        max_score = 0
        for neighbor in adjacency[current_index]:
            if not (used_mask & (1 << neighbor)):
                score = len(word_list[neighbor]) + dfs(neighbor, used_mask | (1 << neighbor))
                if score > max_score:
                    max_score = score
        return max_score

    max_total_score = 0
    for i in range(n):
        score = len(word_list[i]) + dfs(i, 1 << i)
        if score > max_total_score:
            max_total_score = score

    return max_total_score
