def zigzag_iterate(lists, n):
    iterators = [iter(lst) for lst in lists]
    result = []
    while len(result) < n and iterators:
        new_iterators = []
        for it in iterators:
            try:
                result.append(next(it))
                if len(result) == n:
                    break
                new_iterators.append(it)
            except StopIteration:
                continue
        iterators = new_iterators
    return result
