def find_conflict_groups(events):
    def overlaps(event_a, event_b):
        return event_a[1] < event_b[2] and event_b[1] < event_a[2]

    def find_group(event, visited):
        group = [event]
        visited.add(event)
        for other in events:
            if other not in visited and overlaps(event, other):
                group.extend(find_group(other, visited))
        return group

    visited = set()
    groups = []

    for event in events:
        if event not in visited:
            group = find_group(event, visited)
            groups.append(group)

    # Sort groups by the earliest start time of the first event in each group
    groups.sort(key=lambda g: min(event[1] for event in g))
    # Sort events within each group by their start time
    for group in groups:
        group.sort(key=lambda event: event[1])

