    if n <= 0:
        return []
    dq = deque((iter(lst) for lst in lists if lst))
    res = []
    while dq and len(res) < n:
        it = dq.popleft()
        try:
            res.append(next(it))
            dq.append(it)
        except StopIteration:
            pass
    return res

def diagonal_zigzag(matrix):
    if not matrix or not matrix[0]:
        return []
    m, n = len(matrix), len(matrix[0])
    result = []
    for d in range(m + n - 1):
        i_start = max(0, d - (n - 1))
        i_end = min(m - 1, d)
        if d % 2 == 0:
            for i in range(i_start, i_end + 1):
                result.append(matrix[i][d - i])
        else:
            for i in range(i_end, i_start - 1, -1):
                result.append(matrix[i][d - i])
    return result

def water_flow(grid):
    if not grid:
        return []
    m = len(grid)
    n = len(grid[0]) if m > 0 else 0
    if n == 0:
        return [[] for _ in range(m)]

    # Priority order: up, left, right, down
    dirs = [(-1, 0), (0, -1), (0, 1), (1, 0)]
    sinks = [[None] * n for _ in range(m)]

    def next_cell(r, c):
        h = grid[r][c]
        best_h = float('inf')
        best = None
        for dr, dc in dirs:
            nr, nc = r + dr, c + dc
            if 0 <= nr < m and 0 <= nc < n:
                nh = grid[nr][nc]
                if nh < h and nh < best_h:
                    best_h = nh
                    best = (nr, nc)
        return best

    for i in range(m):
        for j in range(n):
            if sinks[i][j] is not None:
                continue
            path = []
            r, c = i, j
            # Follow downhill until we hit a known sink or a local minimum
            while True:
                if sinks[r][c] is not None:
                    sink = sinks[r][c]
                    break
                path.append((r, c))
                nc = next_cell(r, c)
                if nc is None:
                    sink = (r, c)
                    break
                r, c = nc
            # Assign sink to all cells in path
            for pr, pc in path:
                sinks[pr][pc] = sink

    # Convert tuples to [row, col] lists
    return [[ [sinks[i][j][0], sinks[i][j][1]] for j in range(n)] for i in range(m)]

def evaluate_expression(expr):
    class Parser:
        def __init__(self, s):
            self.s = s
            self.i = 0
            self.n = len(s)

        def skip_ws(self):
            while self.i < self.n and self.s[self.i].isspace():
                self.i += 1

        def peek(self):
            self.skip_ws()
            if self.i < self.n:
                return self.s[self.i]
            return None

        def consume(self, ch):
            self.skip_ws()
            if self.i < self.n and self.s[self.i] == ch:
                self.i += 1
                return True
            return False

        def parse_number(self):
            self.skip_ws()
            start = self.i
            if self.i < self.n and (self.s[self.i] == '+' or self.s[self.i] == '-'):
                # This handles numbers with explicit sign as part of number (rare if unary is used)
                self.i += 1
            while self.i < self.n and self.s[self.i].isdigit():
                self.i += 1
            num_str = self.s[start:self.i]
            return int(num_str)

        def parse_factor(self):
            self.skip_ws()
            ch = self.peek()
            if ch is None:
                return 0
            # unary +/-
            if ch == '+' or ch == '-':
                sign = 1
                while True:
                    ch2 = self.peek()
                    if ch2 == '+':
                        self.i += 1
                    elif ch2 == '-':
                        self.i += 1
                        sign *= -1
                    else:
                        break
                    self.skip_ws()
                val = self.parse_factor()
                return sign * val
            if ch == '(':
                self.i += 1  # consume '('
                val = self.parse_expr()
                self.skip_ws()
                if self.i < self.n and self.s[self.i] == ')':
                    self.i += 1
                return val
            # number
            return self.parse_number()

        def parse_term(self):
            val = self.parse_factor()
            while True:
                self.skip_ws()
                if self.i >= self.n:
                    break
                op = self.s[self.i]
                if op not in "*/":
                    break
                self.i += 1
                rhs = self.parse_factor()
                if op == '*':
                    val = val * rhs
                else:
                    # division truncates toward zero
                    val = int(val / rhs)
            return val

        def parse_expr(self):
            val = self.parse_term()
            while True:
                self.skip_ws()
                if self.i >= self.n:
                    break
                op = self.s[self.i]
                if op not in "+-":
                    break
                self.i += 1
                rhs = self.parse_term()
                if op == '+':
                    val = val + rhs
                else:
                    val = val - rhs
            return val

    parser = Parser(expr)
    result = parser.parse_expr()
    parser.skip_ws()
    return result

def spiral_coords(n):
    if n < 1:
        raise ValueError("n must be a positive integer (1-indexed).")
    if n == 1:
        return (0, 0)
    x = y = 0
    steps_remaining = n - 1  # moves to make from (0,0)
    dirs = [(1, 0), (0, 1), (-1, 0), (0, -1)]  # right, up, left, down
    dir_idx = 0
    seg_len = 1
    segments_done = 0
    while steps_remaining > 0:
        dx, dy = dirs[dir_idx]
        to_move = min(seg_len, steps_remaining)
        x += dx * to_move
        y += dy * to_move
        steps_remaining -= to_move
        dir_idx = (dir_idx + 1) % 4
        segments_done += 1
        if segments_done % 2 == 0:
            seg_len += 1
    return (x, y)

def find_conflict_groups(events):
    if not events:
        return []
    events_sorted = sorted(events, key=lambda e: (e[1], e[2], e[0]))
    groups = []
    current_group = [events_sorted[0]]
    current_end = events_sorted[0][2]
    for ev in events_sorted[1:]:
        start, end = ev[1], ev[2]
        if start < current_end:
            current_group.append(ev)
            if end > current_end:
                current_end = end
        else:
            groups.append(current_group)
            current_group = [ev]
            current_end = end
    groups.append(current_group)
    return groups

