        if isinstance(obj, dict):
            for k, v in obj.items():
                k_str = str(k)
                new_pref = f"{pref}.{k_str}" if pref else k_str
                _flatten(v, new_pref)
        elif isinstance(obj, list):
            for i, v in enumerate(obj):
                new_pref = f"{pref}[{i}]" if pref else f"[{i}]"
                _flatten(v, new_pref)
        else:
            out[pref] = obj
    _flatten(d, prefix if prefix else "")
    return out

