            pair[a] = b
            pair[b] = a
    # Dijkstra (weights 1 and 2)
    INF = 10**12
    dist = [[INF] * n for _ in range(n)]
    dist[0][0] = 0
    heap = [(0, 0, 0)]
    while heap:
        d, r, c = heapq.heappop(heap)
        if d != dist[r][c]:
            continue
        if (r, c) == (n - 1, n - 1):
            return d
        for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            nr, nc = r + dr, c + dc
