    n = len(words)
    lens = [len(w) for w in words]
    starts = [w[0] for w in words]
    ends = [w[-1] for w in words]
    start_map = {}
    for i, s in enumerate(starts):
        start_map.setdefault(s, []).append(i)
    adj = [start_map.get(e, [])[:] for e in ends]  # neighbors by index

    # Use bitmask DP when n is small enough for memoization, otherwise backtracking.
    if n <= 20:
        from functools import lru_cache
        @lru_cache(None)
        def dfs(i, mask):
