def word_chain_score(words):
    from collections import defaultdict

    # Create a graph where each node is a word and edges connect words that can follow each other
    graph = defaultdict(list)
    word_to_length = {word: len(word) for word in words}

    # Populate the graph
    for word in words:
        last_char = word[-1]
        for potential_next in words:
            if potential_next != word and potential_next[0] == last_char:
                graph[word].append(potential_next)

    # Function to find the maximum score using DFS
    def dfs(word, visited):
        max_score = word_to_length[word]
        for neighbor in graph[word]:
            if neighbor not in visited:
                visited.add(neighbor)
                max_score = max(max_score, word_to_length[word] + dfs(neighbor, visited))
                visited.remove(neighbor)
        return max_score

    # Try starting the chain from each word and find the maximum score
    max_score = 0
    for word in words:
        visited = set([word])
        max_score = max(max_score, dfs(word, visited))

    return max_score
