def word_chain_score(words):
    from functools import lru_cache

    n = len(words)
    if n == 0:
        return 0

    first = [w[0] for w in words]
    last = [w[-1] for w in words]
    length = [len(w) for w in words]

    # build adjacency: i -> j if last letter of i matches first of j
    adj = [[] for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if i != j and last[i] == first[j]:
                adj[i].append(j)

    @lru_cache(None)
    def dfs(cur, used_mask):
        best = 0
        for nxt in adj[cur]:
            bit = 1 << nxt
            if not (used_mask & bit):
                score = length[nxt] + dfs(nxt, used_mask | bit)
                if score > best:
                    best = score
        return best

    # try each word as the start of the chain
    best_score = 0
    for i in range(n):
        score = length[i] + dfs(i, 1 << i)
        if score > best_score:
            best_score = score

    return best_score

