def zigzag_iterate(lists, n):
    from collections import deque
    result = []
    queue = deque(iter(lst) for lst in lists)
    while queue and len(result) < n:
        it = queue.popleft()
        try:
            result.append(next(it))
            queue.append(it)
        except StopIteration:
            pass
    return result

def bracket_depth_map(s):
    depth = 0
    res = []
    for ch in s:
        if ch == '(':
            depth += 1
            res.append(depth)
        elif ch == ')':
            res.append(depth)
            depth -= 1
            if depth < 0:
                return [-1]
        else:
            res.append(depth)
    if depth != 0:
        return [-1]
    return res

def zigzag_iterate(lists, n):
    if n <= 0:
        return []
    iters = [iter(lst) for lst in lists]
    active = [True] * len(lists)
    result = []
    while len(result) < n:
        progressed = False
        for i in range(len(lists)):
            if not active[i]:
                continue
            try:
                val = next(iters[i])
                result.append(val)
                progressed = True
                if len(result) == n:
                    return result
            except StopIteration:
                active[i] = False
        if not progressed:
            break
    return result

