def evaluate_expression(expr):
    s = expr
    n = len(s)
    i = 0

    def skip():
        nonlocal i
        while i < n and s[i].isspace():
            i += 1

    def parse_factor():
        nonlocal i
        skip()
        # Unary plus/minus
        if i < n and s[i] in '+-':
            sign = 1
            if s[i] == '-':
                sign = -1
            i += 1
            val = parse_factor()
            return sign * val

        skip()
        if i < n and s[i] == '(':
            i += 1
            val = parse_expr()
            skip()
            if i < n and s[i] == ')':
                i += 1
            return val

        start = i
        if i < n and s[i].isdigit():
            while i < n and s[i].isdigit():
                i += 1
            return int(s[start:i])

        # Should not reach here for valid input
        return 0

    def parse_term():
        nonlocal i
        left = parse_factor()
        while True:
            skip()
            if i < n and s[i] in '*/':
                op = s[i]
                i += 1
                right = parse_factor()
                if op == '*':
                    left = left * right
                else:
                    left = int(left / right)  # truncates toward zero
            else:
                break
        return left

    def parse_expr():
        nonlocal i
        left = parse_term()
        while True:
            skip()
            if i < n and s[i] in '+-':
                op = s[i]
                i += 1
                right = parse_term()
                if op == '+':
                    left = left + right
                else:
                    left = left - right
            else:
                break
        return left

    return parse_expr()

def water_flow(grid):
    if not grid or not grid[0]:
        return []
    import sys
    sys.setrecursionlimit(1000000)

    R, C = len(grid), len(grid[0])
    sink = [[None for _ in range(C)] for _ in range(R)]
    # Priority order for tie-breaking: up, left, right, down
    priority = [(-1, 0), (0, -1), (0, 1), (1, 0)]

    def find(r, c):
        if sink[r][c] is not None:
            return sink[r][c]
        h = grid[r][c]

        # Find the minimum height among strictly lower neighbors
        min_h = None
        for dr, dc in priority:
            nr, nc = r + dr, c + dc
            if 0 <= nr < R and 0 <= nc < C:
                nh = grid[nr][nc]
                if nh < h:
                    if min_h is None or nh < min_h:
                        min_h = nh

        # If no strictly lower neighbor, this is a pool
        if min_h is None:
            sink[r][c] = (r, c)
            return (r, c)

        # Among neighbors with height equal to min_h, pick by priority order
        chosen = None
        for dr, dc in priority:
            nr, nc = r + dr, c + dc
            if 0 <= nr < R and 0 <= nc < C:
                if grid[nr][nc] == min_h:
                    chosen = (nr, nc)
                    break

        dest = find(chosen[0], chosen[1])
        sink[r][c] = dest
        return dest

    result = [[None for _ in range(C)] for _ in range(R)]
    for i in range(R):
        for j in range(C):
            dest = find(i, j)
            result[i][j] = [dest[0], dest[1]]
    return result

def word_chain_score(words):
    if not words:
        return 0

    n = len(words)
    first = [w[0] for w in words]
    last = [w[-1] for w in words]
    length = [len(w) for w in words]

    # Precompute possible next indices for each i
    edges = [
        [k for k in range(n) if k != i and first[k] == last[i]]
        for i in range(n)
    ]

    from functools import lru_cache

    @lru_cache(None)
    def dfs(i, mask):
        best = 0
        for j in edges[i]:
            if not (mask & (1 << j)):
                val = dfs(j, mask | (1 << j))
                if val > best:
                    best = val
        return length[i] + best

    ans = 0
    for i in range(n):
        ans = max(ans, dfs(i, 1 << i))
    return ans

def teleporter_bfs(grid):
    from heapq import heappush, heappop

    if not grid or not grid[0]:
        return -1
    n = len(grid)
    if grid[0][0] == 1:
        return -1

    # Build teleporter mapping: number -> list of coordinates
    tele_coords = {}
    for r in range(n):
        for c in range(n):
            v = grid[r][c]
            if v >= 2:
                tele_coords.setdefault(v, []).append((r, c))

    # Map each teleporter cell to its pair cell
    pair_map = {}
    for v, coords in tele_coords.items():
        if len(coords) == 2:
            (r1, c1), (r2, c2) = coords[0], coords[1]
            pair_map[(r1, c1)] = (r2, c2)
            pair_map[(r2, c2)] = (r1, c1)

    INF = 10**9
    dist = [[INF] * n for _ in range(n)]
    dist[0][0] = 0
    heap = [(0, 0, 0)]
